// Map go-wa webhook payload -> flat columns. go-wa sends { event, payload:{…} }
// and n8n's Webhook node wraps the POST body under .body. Unwrap both, then read
// the message fields. Fallbacks cover older/flat go-wa shapes. Full go-wa object
// kept in `raw` so you can adjust mappings if your version differs.
const root = $json.body ?? $json;
const p = root.payload ?? root;

const chat_jid =
  p.chat_id || p.chatId || p.chatID ||
  (typeof p.from === 'string' && p.from.includes('@g.us') ? p.from : '') || '';
const sender_jid = p.from || p.sender_id || p.senderId || p.participant || '';
const sender_name = p.from_name || p.pushname || p.push_name || p.sender_name || p.notify || 'Unknown';

let media_type = null;
if (p.image) media_type = 'image';
else if (p.video) media_type = 'video';
else if (p.audio) media_type = 'audio';
else if (p.document) media_type = 'document';
else if (p.sticker) media_type = 'sticker';
else if (p.location) media_type = 'location';

const caption =
  (p.image && p.image.caption) || (p.video && p.video.caption) ||
  (p.document && p.document.caption) || '';
const text =
  p.body || p.text || p.caption ||
  (p.message && (p.message.text ?? p.message.conversation)) || caption || '';
const message = media_type && !text ? '[' + media_type + ']' : text;

const message_id = p.id || (p.message && p.message.id) || null;

// go-wa timestamp may be Unix seconds, Unix ms, or an ISO string. Parse robustly
// (a raw Unix-seconds number through new Date() would land in 1970 and break the
// "today" filter). Fall back to now on anything unparseable.
let ts;
const rawTs = p.timestamp;
if (rawTs === null || rawTs === undefined || rawTs === '') {
  ts = new Date().toISOString();
} else if (typeof rawTs === 'number' || /^\d+$/.test(String(rawTs))) {
  const n = Number(rawTs);
  ts = new Date(n < 1e12 ? n * 1000 : n).toISOString();
} else {
  const d = new Date(rawTs);
  ts = isNaN(d.getTime()) ? new Date().toISOString() : d.toISOString();
}

return [{ json: {
  message_id: message_id || null,
  chat_jid, sender_jid, sender_name, message, media_type,
  is_group: String(chat_jid).endsWith('@g.us'),
  timestamp: ts,
  raw: JSON.stringify(root),
} }];
